    path: '/en/basic/field/advanced/formula/cheat-sheet',
    url: 'https://help.teable.ai/en/basic/field/advanced/formula/cheat-sheet',
    title: 'Function Cheat Sheet',
    description:
      'This section provides a quick reference for all available functions and their basic usage',
